 90→  initialLoading?: boolean;
 91→  onChartSelection?: (
 92→    timeSpan: TimeSpan,
 93→    selection: { name: string; series: string; value: number }
 94→  ) => void;
 95→  /** Whether to show edit controls for sections (custom dashboards) */
 96→  showSectionEditControls?: boolean;
 97→  /** Callback when section is renamed */
 98→  onSectionRename?: (sectionIndex: number, newTitle: string) => void;
 99→  /** Callback when section is deleted */
100→  onSectionDelete?: (sectionIndex: number) => void;
101→  /** Callback when section collapse state changes */
102→  onSectionCollapseChange?: (sectionIndex: number, collapsed: boolean) => void;
103→  /**
104→   * Children to render below the dashboard panels.
105→   * Children can use the useDashboardRefresh hook to register
106→   * themselves for automatic refresh when the dashboard refreshes.
107→   */
108→  children?: React.ReactNode;
109→}
