138→/** Represents a section with its panels and metadata */
139→interface SectionInfo {
140→  group: DashboardGroup | null; // null for ungrouped panels
141→  sectionIndex: number;
142→  panels: PanelDescriptor[];
143→  globalPanelStartIndex: number; // Global index of first panel in this section
144→}
145→
146→const DashboardPanelContainer = forwardRef<
147→  DashboardPanelContainerRef,
148→  DashboardPanelContainerProps
149→>(
150→  (
151→    {
152→      dashboard,
153→      dashboardId,
154→      initialTimeSpan,
155→      initialFilterExpression,
156→      initialLoading,
157→      onChartSelection,
158→      showSectionEditControls = false,
159→      onSectionRename,
160→      onSectionDelete,
161→      onSectionCollapseChange,
162→      children,
163→    },
164→    ref
165→  ) => {
166→    // Track individual panel collapse states (keyed by global panel index)
167→    const [panelCollapseStates, setPanelCollapseStates] = useState<Map<number, boolean>>(new Map());
168→    // Track section collapse states (keyed by section index) - local state, not persisted
169→    const [sectionCollapseStates, setSectionCollapseStates] = useState<Map<number, boolean>>(new Map());
170→    const subComponentRefs = useRef<(DashboardVisualizationComponent | null)[]>([]);
171→
172→    // Track registered refreshable children
173→    const registeredChildrenRef = useRef<Set<RefreshableChild>>(new Set());
174→
175→    // Memoize the charts array from the dashboard
176→    const panels = useMemo(() => dashboard.charts, [dashboard]);
177→
178→    // Build sections from dashboard panels
179→    const sections = useMemo<SectionInfo[]>(() => {
180→      const result: SectionInfo[] = [];
181→      const ungroupedPanels: PanelDescriptor[] = [];
182→      let globalPanelIndex = 0;
183→      let sectionIndex = 0;
184→
185→      panels.forEach((item) => {
186→        if (isDashboardGroup(item)) {
187→          // This is a group - create a section for it
188→          result.push({
189→            group: item,
190→            sectionIndex,
191→            panels: item.charts,
192→            globalPanelStartIndex: globalPanelIndex,
193→          });
194→          globalPanelIndex += item.charts.length;
195→          sectionIndex++;
196→        } else {
197→          // Standalone panel - collect into ungrouped
198→          ungroupedPanels.push(item);
199→        }
200→      });
201→
202→      // If there are ungrouped panels, add them as the last section (without header)
203→      if (ungroupedPanels.length > 0) {
204→        // Find the correct global start index for ungrouped panels
205→        // They may be interleaved with groups, so we need to recalculate
206→        let ungroupedStartIndex = 0;
207→        panels.forEach((item) => {
208→          if (isDashboardGroup(item)) {
209→            ungroupedStartIndex += item.charts.length;
210→          }
211→        });
212→
213→        result.push({
214→          group: null, // null indicates ungrouped section
215→          sectionIndex,
216→          panels: ungroupedPanels,
217→          globalPanelStartIndex: ungroupedStartIndex,
218→        });
219→      }
220→
221→      return result;
222→    }, [panels]);
223→
224→    // Initialize panel collapse states from descriptors
225→    useEffect(() => {
226→      setPanelCollapseStates((prev) => {
227→        const next = new Map(prev);
228→        let changed = false;
229→        sections.forEach((section) => {
230→          section.panels.forEach((panel, localIndex) => {
231→            const globalIndex = section.globalPanelStartIndex + localIndex;
232→            if (!prev.has(globalIndex)) {
233→              next.set(globalIndex, panel.collapsed ?? false);
234→              changed = true;
235→            }
236→          });
237→        });
238→        return changed ? next : prev;
239→      });
240→    }, [sections]);
241→
242→    // Store callback in ref to avoid stale closure in setState
243→    const onSectionCollapseChangeRef = useRef(onSectionCollapseChange);
244→    onSectionCollapseChangeRef.current = onSectionCollapseChange;
245→
246→    // Store sections in ref to access current value in toggle handler
247→    const sectionsRef = useRef(sections);
248→    sectionsRef.current = sections;
249→
250→    // Track pending collapse change to notify parent after state update
251→    const pendingCollapseChangeRef = useRef<{ sectionIndex: number; collapsed: boolean } | null>(null);
252→
253→    // Toggle section collapse - uses local state, optionally notifies parent
254→    const handleSectionToggle = useCallback((sectionIndex: number) => {
255→      console.log('[handleSectionToggle] Called for section:', sectionIndex);
256→      const section = sectionsRef.current.find(s => s.sectionIndex === sectionIndex);
257→      const configCollapsed = section?.group?.collapsed ?? false;
258→
259→      setSectionCollapseStates((prev) => {
260→        const currentCollapsed = prev.has(sectionIndex) ? prev.get(sectionIndex)! : configCollapsed;
261→        const newCollapsed = !currentCollapsed;
262→        console.log('[handleSectionToggle] Previous state:', currentCollapsed, '-> New state:', newCollapsed);
263→
264→        // Store pending change to notify parent after render
265→        pendingCollapseChangeRef.current = { sectionIndex, collapsed: newCollapsed };
266→
267→        const next = new Map(prev);
268→        next.set(sectionIndex, newCollapsed);
269→        return next;
270→      });
271→    }, []);
272→
273→    // Notify parent after state update settles
274→    useEffect(() => {
275→      if (pendingCollapseChangeRef.current) {
276→        const { sectionIndex, collapsed } = pendingCollapseChangeRef.current;
277→        pendingCollapseChangeRef.current = null;
278→        onSectionCollapseChangeRef.current?.(sectionIndex, collapsed);
279→      }
280→    }, [sectionCollapseStates]);
281→
282→    const onPanelCollapsedChange = useCallback((globalPanelIndex: number, isCollapsed: boolean) => {
283→      setPanelCollapseStates((prev) => {
284→        const next = new Map(prev);
285→        next.set(globalPanelIndex, isCollapsed);
286→        return next;
287→      });
288→    }, []);
289→
290→    // Function to connect all chart instances together
291→    const connectAllCharts = useCallback(() => {
292→      const chartInstances: echarts.ECharts[] = subComponentRefs.current
293→        .filter(
294→          (chartRef): chartRef is DashboardVisualizationComponent =>
295→            chartRef !== null &&
296→            typeof (chartRef as unknown as { getEChartInstance?: () => echarts.ECharts })
297→              .getEChartInstance === "function"
298→        )
299→        .map((chartRef) => {
300→          const component = chartRef as unknown as { getEChartInstance: () => echarts.ECharts };
301→          return component.getEChartInstance();
302→        })
303→        .filter((echartInstance) => echartInstance !== undefined);
304→
305→      if (chartInstances.length === 0) {
306→        return;
307→      }
308→
309→      const allCharts = getAllCharts(panels);
310→      const chartNumber = allCharts.filter(
311→        (chart: PanelDescriptor) => chart.type !== "table"
312→      ).length;
313→      if (chartInstances.length === chartNumber) {
314→        // Connect all echarts together on this page
315→        connect(chartInstances);
316→      }
317→    }, [panels]);
318→
319→    // Callback when a subcomponent is mounted or unmounted
320→    const onSubComponentUpdated = useCallback(
321→      (subComponent: DashboardVisualizationComponent | null, globalIndex: number) => {
322→        subComponentRefs.current[globalIndex] = subComponent;
323→        connectAllCharts();
324→      },
325→      [connectAllCharts]
326→    );
327→
328→    const refreshAllCharts = useCallback(
329→      (newTimeSpan?: TimeSpan, newFilterExpression?: string) => {
330→        const refreshParam: RefreshOptions = {
331→          timeSpan: newTimeSpan ?? initialTimeSpan,
332→          filterExpression: newFilterExpression ?? initialFilterExpression,
333→          forceRefresh: true,
334→        };
335→
336→        subComponentRefs.current.forEach((chart) => {
337→          if (chart !== null) {
338→            chart.refresh(refreshParam);
339→          }
340→        });
341→
342→        // Also refresh all registered child components
343→        registeredChildrenRef.current.forEach((child) => {
344→          child.refresh(
345→            newTimeSpan ?? initialTimeSpan,
346→            newFilterExpression ?? initialFilterExpression
347→          );
348→        });
349→      },
350→      [initialTimeSpan, initialFilterExpression]
351→    );
352→
353→    // Expose refresh method via imperative handle
354→    useImperativeHandle(
355→      ref,
356→      () => ({
357→        refresh: (timeSpan?: TimeSpan, filterExpression?: string) => {
358→          refreshAllCharts(timeSpan, filterExpression);
359→        },
360→      }),
361→      [refreshAllCharts]
362→    );
363→
364→    // Context value for child registration
365→    const contextValue = useMemo<DashboardRefreshContextValue>(
366→      () => ({
367→        register: (child: RefreshableChild) => {
368→          registeredChildrenRef.current.add(child);
369→        },
370→        unregister: (child: RefreshableChild) => {
371→          registeredChildrenRef.current.delete(child);
372→        },
373→      }),
374→      []
375→    );
376→
377→    // Generate a stable dashboard ID for layout persistence
378→    const effectiveDashboardId = dashboardId ?? dashboard.name ?? "default";
379→
380→    return (
381→      <DashboardRefreshContext.Provider value={contextValue}>
382→        <div className="h-full flex flex-col overflow-hidden">
383→          <div className="flex-1 overflow-y-auto overflow-x-hidden">
384→            {sections.map((section) => {
385→              // Use local state for collapse only (no persistence)
386→              const isCollapsed = sectionCollapseStates.get(section.sectionIndex) ?? false;
387→              console.log('[Container] Rendering section:', section.sectionIndex, 'isCollapsed:', isCollapsed, 'stateMap:', Array.from(sectionCollapseStates.entries()));
388→
389→              return (
390→                <DashboardSection
391→                  key={`section-${section.sectionIndex}`}
392→                  dashboardId={effectiveDashboardId}
393→                  sectionIndex={section.sectionIndex}
394→                  group={section.group}
395→                  panels={section.panels}
396→                  isCollapsed={isCollapsed}
397→                  onToggleCollapse={() => handleSectionToggle(section.sectionIndex)}
398→                  onSubComponentUpdated={onSubComponentUpdated}
399→                  globalPanelStartIndex={section.globalPanelStartIndex}
400→                  initialTimeSpan={initialTimeSpan}
401→                  initialFilterExpression={initialFilterExpression}
402→                  initialLoading={initialLoading}
403→                  panelCollapseStates={panelCollapseStates}
404→                  onPanelCollapsedChange={onPanelCollapsedChange}
405→                  onChartSelection={onChartSelection}
406→                  showEditControls={showSectionEditControls && section.group !== null}
407→                  onRename={onSectionRename ? (title) => onSectionRename(section.sectionIndex, title) : undefined}
408→                  onDelete={onSectionDelete ? () => onSectionDelete(section.sectionIndex) : undefined}
409→                />
410→              );
411→            })}
412→            {children}
413→          </div>
414→        </div>
415→      </DashboardRefreshContext.Provider>
416→    );
417→  }
418→);
419→
420→export default DashboardPanelContainer;
