 25→  PieDescriptor,
 26→  StatDescriptor,
 27→  TableDescriptor,
 28→  TimeseriesDescriptor,
 29→  TransposeTableDescriptor,
 30→} from "./dashboard-model";
 31→// Import pure visualization components
 32→import { GaugeVisualization, type GaugeVisualizationRef } from "./dashboard-visualization-gauge";
