 53→/**
 54→ * Minimum display time for skeleton loaders (in milliseconds)
 55→ * This ensures skeleton doesn't flash on fast loads for better UX
 56→ */
 57→export const SKELETON_MIN_DISPLAY_TIME = 1_000;
 58→
 59→/**
 60→ * Fade transition duration for skeleton loaders (in milliseconds)
 61→ */
 62→export const SKELETON_FADE_DURATION = 150;
