853→                selectedTimeSpan={props.initialTimeSpan}
854→                onChartSelection={props.onChartSelection}
855→              />
856→            ) : typedDescriptor.type === "gauge" ? (
857→              <GaugeVisualization
858→                ref={visualizationRef as React.Ref<GaugeVisualizationRef>}
859→                data={data}
860→                meta={meta}
861→                descriptor={typedDescriptor as GaugeDescriptor}
862→                selectedTimeSpan={props.initialTimeSpan}
863→              />
