  dashboardId,
  sectionIndex,
  group,
  panels,
  isCollapsed,
  onToggleCollapse,
  onSubComponentUpdated,
  globalPanelStartIndex,
  initialTimeSpan,
  initialFilterExpression,
  initialLoading,
